class Pin:
    IN, OUT = "IN", "OUT"

    def __init__(self, number, mode):
        self.number = number
        self.mode = mode
        self._value = 0

    def value(self, v=None):
        if v is None:
            return self._value
        self._value = v

LED = Pin(2, Pin.OUT)
PIR = Pin(13, Pin.IN)

감지_기록 = [0, 0, 1, 1, 0, 1, 0]  # 1이면 사람 감지됨(실제 ESP32에서는 센서가 실시간으로 이 값을 알려준다)

for 순간, 감지됨 in enumerate(감지_기록):
    PIR.value(감지됨)
    if PIR.value() == 1:
        LED.value(1)
    else:
        LED.value(0)
    상태 = "켜짐" if LED.value() == 1 else "꺼짐"
    print(f"{순간}초: 사람 감지={PIR.value()} -> LED {상태}")
